package com.trademaster.ims.mobile.orders.service;
import com.trademaster.ims.mobile.auth.security.CustomerAuthentication;import com.trademaster.ims.mobile.auth.service.CustomerAuthException;import com.trademaster.ims.mobile.notifications.service.CustomerNotificationService;import com.trademaster.ims.mobile.checkout.model.*;import com.trademaster.ims.mobile.checkout.repository.*;import com.trademaster.ims.mobile.orders.dto.OrderDtos.*;import com.trademaster.ims.mobile.orders.model.*;import com.trademaster.ims.mobile.orders.repository.*;import jakarta.persistence.criteria.Predicate;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.beans.factory.annotation.Value;import org.springframework.data.domain.*;import org.springframework.data.jpa.domain.Specification;import org.springframework.http.HttpStatus;import org.springframework.security.core.Authentication;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import org.springframework.util.StringUtils;import java.math.BigDecimal;import java.time.*;import java.time.format.DateTimeFormatter;import java.util.*;import java.util.stream.Collectors;
@Service @Transactional public class MobileOrderService{private final CustomerOrderRepository orders;private final CustomerOrderItemRepository items;private final CustomerOrderStatusHistoryRepository history;private final CustomerOrderCancellationRequestRepository cancellations;private final CustomerReturnRequestRepository returns;private final CustomerReturnRequestItemRepository returnItems;private final int returnWindowDays;@Autowired(required=false) private CustomerNotificationService notifications;
 public MobileOrderService(CustomerOrderRepository o,CustomerOrderItemRepository i,CustomerOrderStatusHistoryRepository h,CustomerOrderCancellationRequestRepository c,CustomerReturnRequestRepository r,CustomerReturnRequestItemRepository ri,@Value("${techsmart.orders.return-window-days:7}")int days){orders=o;items=i;history=h;cancellations=c;returns=r;returnItems=ri;returnWindowDays=days;}
 public long account(Authentication a){if(a instanceof CustomerAuthentication c)return c.accountId();throw err(HttpStatus.UNAUTHORIZED,"AUTHENTICATION_REQUIRED","Customer authentication is required.");}
 @Transactional(readOnly=true)public OrderPage list(long account,int page,int size,String orderStatus,String paymentStatus,String dateFrom,String dateTo,String query,String sort){int s=Math.max(1,Math.min(size<=0?10:size,50));Pageable p=PageRequest.of(Math.max(0,page),s,sort(sort));Specification<CustomerOrder>spec=(root,q,cb)->{List<Predicate>ps=new ArrayList<>();ps.add(cb.equal(root.get("accountId"),account));if(StringUtils.hasText(orderStatus))ps.add(cb.equal(root.get("status"),parseOrderStatus(orderStatus)));if(StringUtils.hasText(paymentStatus))ps.add(cb.equal(root.get("paymentStatus"),parsePaymentStatus(paymentStatus)));if(StringUtils.hasText(dateFrom))ps.add(cb.greaterThanOrEqualTo(root.get("submittedAt"),LocalDate.parse(dateFrom).atStartOfDay().toInstant(ZoneOffset.UTC)));if(StringUtils.hasText(dateTo))ps.add(cb.lessThan(root.get("submittedAt"),LocalDate.parse(dateTo).plusDays(1).atStartOfDay().toInstant(ZoneOffset.UTC)));if(StringUtils.hasText(query))ps.add(cb.like(cb.lower(root.get("orderNumber")),"%"+query.trim().toLowerCase()+"%"));return cb.and(ps.toArray(Predicate[]::new));};Page<CustomerOrder>pg=orders.findAll(spec,p);List<OrderSummary>content=pg.getContent().stream().map(this::summary).toList();return new OrderPage(content,pg.getNumber(),pg.getSize(),pg.getTotalElements(),pg.getTotalPages(),pg.isFirst(),pg.isLast());}
 @Transactional(readOnly=true)public OrderDetail detail(long account,String number){CustomerOrder o=order(account,number);return detail(o);}
 @Transactional(readOnly=true)public List<TimelineEntry>timeline(long account,String number){return timeline(order(account,number));}
 @Transactional(readOnly=true)public EligibilityResponse cancellationEligibility(long account,String number){return cancellationEligibility(order(account,number));}
 public CancellationRequestResponse cancel(long account,String number,CancellationRequestDto q){CustomerOrder o=order(account,number);Optional<CustomerOrderCancellationRequest>prior=cancellations.findByAccountIdAndIdempotencyKey(account,q.idempotencyKey());if(prior.isPresent()){if(!Objects.equals(prior.get().getOrderId(),o.getId()))throw err(HttpStatus.CONFLICT,"IDEMPOTENCY_CONFLICT","Idempotency key was used for another cancellation request.");notifyCancellation(o);return cancellationResponse(o,prior.get());}EligibilityResponse e=cancellationEligibility(o);if(!e.eligible())throw err(HttpStatus.CONFLICT,e.reasonCode(),e.message());CustomerOrderCancellationRequest.ReasonCode reason=reason(q.reasonCode());String text=clean(q.reasonText());if(reason==CustomerOrderCancellationRequest.ReasonCode.OTHER&&!StringUtils.hasText(text))throw err(HttpStatus.BAD_REQUEST,"REASON_REQUIRED","Please explain the cancellation reason.");if(!cancellations.findByOrderIdAndStatusIn(o.getId(),List.of(CustomerOrderCancellationRequest.Status.REQUESTED,CustomerOrderCancellationRequest.Status.UNDER_REVIEW)).isEmpty())throw err(HttpStatus.CONFLICT,"CANCELLATION_ALREADY_REQUESTED","A cancellation request is already active for this order.");CustomerOrderCancellationRequest r=new CustomerOrderCancellationRequest();r.setOrderId(o.getId());r.setAccountId(account);r.setReasonCode(reason);r.setReasonText(text);r.setIdempotencyKey(q.idempotencyKey());r=cancellations.save(r);CustomerOrderStatusHistory h=new CustomerOrderStatusHistory();h.setOrderId(o.getId());h.setStatus("CANCELLATION_REQUESTED");h.setCustomerNote("Cancellation requested by customer.");history.save(h);notifyCancellation(o);return cancellationResponse(o,r);}
 @Transactional(readOnly=true)public Optional<CancellationRequestResponse>existingCancellation(long account,String number){CustomerOrder o=order(account,number);return cancellations.findTopByOrderIdOrderByRequestedAtDesc(o.getId()).map(r->cancellationResponse(o,r));}
 @Transactional(readOnly=true)public ReturnEligibilityResponse returnEligibility(long account,String number){return returnEligibility(order(account,number));}
 public ReturnRequestResponse createReturn(long account,String number,ReturnRequestDto q){CustomerOrder o=order(account,number);Optional<CustomerReturnRequest>prior=returns.findByAccountIdAndIdempotencyKey(account,q.idempotencyKey());if(prior.isPresent()){if(!Objects.equals(prior.get().getOrderId(),o.getId()))throw err(HttpStatus.CONFLICT,"IDEMPOTENCY_CONFLICT","Idempotency key was used for another return request.");notifyReturn(o,prior.get());return returnResponse(o,prior.get());}ReturnEligibilityResponse e=returnEligibility(o);if(!e.eligible())throw err(HttpStatus.CONFLICT,e.reasonCode(),e.message());Map<Long,CustomerOrderItem>map=items.findByOrderIdOrderByIdAsc(o.getId()).stream().collect(Collectors.toMap(CustomerOrderItem::getId,x->x));CustomerReturnRequest req=new CustomerReturnRequest();req.setRequestNumber(returnNumber());req.setOrderId(o.getId());req.setAccountId(account);req.setStatus(CustomerReturnRequest.Status.REQUESTED);req.setPreferredResolution(resolution(q.preferredResolution()));req.setCustomerComment(clean(q.customerComment()));req.setIdempotencyKey(q.idempotencyKey());req.setReasonSummary("Customer return request");req=returns.saveAndFlush(req);for(ReturnItemRequest in:q.items()){CustomerOrderItem oi=map.get(in.orderItemId());if(oi==null)throw err(HttpStatus.BAD_REQUEST,"RETURN_ITEM_INVALID","Selected item does not belong to this order.");int remaining=remainingReturnable(oi);if(in.quantity()>remaining)throw err(HttpStatus.BAD_REQUEST,"RETURN_QUANTITY_INVALID","Requested return quantity exceeds the returnable quantity.");CustomerReturnRequestItem.ReasonCode rc=returnReason(in.reasonCode());String text=clean(in.reasonText());if(rc==CustomerReturnRequestItem.ReasonCode.OTHER&&!StringUtils.hasText(text))throw err(HttpStatus.BAD_REQUEST,"REASON_REQUIRED","Please explain the return reason.");CustomerReturnRequestItem item=new CustomerReturnRequestItem();item.setReturnRequestId(req.getId());item.setOrderItemId(oi.getId());item.setRequestedQuantity(in.quantity());item.setReasonCode(rc);item.setReasonText(text);returnItems.save(item);}CustomerOrderStatusHistory h=new CustomerOrderStatusHistory();h.setOrderId(o.getId());h.setStatus("RETURN_REQUESTED");h.setCustomerNote("Return requested by customer.");history.save(h);notifyReturn(o,req);return returnResponse(o,req);}
 @Transactional(readOnly=true)public ReturnRequestResponse getReturn(long account,String requestNumber){CustomerReturnRequest r=returns.findByRequestNumberAndAccountId(requestNumber,account).orElseThrow(()->err(HttpStatus.NOT_FOUND,"RETURN_REQUEST_NOT_FOUND","Return request was not found."));CustomerOrder o=orders.findById(r.getOrderId()).orElseThrow();return returnResponse(o,r);}
 @Transactional(readOnly=true)public OrderDocumentResponse document(long account,String number){CustomerOrder o=order(account,number);List<CustomerOrderItem>its=items.findByOrderIdOrderByIdAsc(o.getId());String title="Order Summary / Pro Forma - "+o.getOrderNumber();StringBuilder rows=new StringBuilder();for(CustomerOrderItem i:its){rows.append("<tr><td>").append(esc(i.getProductName())).append("</td><td>").append(esc(nullToEmpty(i.getProductCode()))).append("</td><td>").append(i.getQuantity()).append("</td><td>").append(money(i.getUnitPrice())).append("</td><td>").append(money(i.getLineSubtotal())).append("</td></tr>");}String html="<!doctype html><html><body><h1>"+esc(title)+"</h1><p>Status: "+esc(o.getStatus().name())+"</p><p>Payment: "+esc(o.getPaymentStatus().name())+" (payment not started)</p><p>Submitted: "+o.getSubmittedAt()+"</p><p>Delivery: "+esc(o.getDeliverySnapshot())+"</p><p>Address: "+esc(o.getAddressSnapshot())+"</p><table><thead><tr><th>Product</th><th>SKU</th><th>Qty</th><th>Unit</th><th>Line</th></tr></thead><tbody>"+rows+"</tbody></table><p>Subtotal: "+money(o.getSubtotal())+"</p><p>Tax: "+money(o.getTax())+"</p><p>Delivery: "+money(o.getDelivery())+"</p><h2>Grand Total: "+money(o.getTotal())+"</h2><p>This is not a paid invoice or payment receipt.</p></body></html>";return new OrderDocumentResponse(o.getOrderNumber(),safeFile(o.getOrderNumber())+"-order-summary.html","text/html",title,html);}
 private void notifyCancellation(CustomerOrder o){if(notifications!=null)notifications.cancellationRequested(o.getAccountId(),o.getOrderNumber());}
 private void notifyReturn(CustomerOrder o,CustomerReturnRequest r){if(notifications!=null)notifications.returnRequested(o.getAccountId(),o.getOrderNumber(),r.getRequestNumber());}
 private CustomerOrder order(long account,String n){return orders.findByOrderNumberAndAccountId(n,account).orElseThrow(()->err(HttpStatus.NOT_FOUND,"ORDER_NOT_FOUND","Order was not found."));}
 private OrderDetail detail(CustomerOrder o){List<CustomerOrderItem>its=items.findByOrderIdOrderByIdAsc(o.getId());return new OrderDetail(o.getOrderNumber(),o.getSubmittedAt(),o.getUpdatedAt(),o.getStatus().name(),label(o.getStatus().name()),o.getPaymentStatus().name(),o.getAccountingStatus().name(),"BDT",o.getSubtotal(),o.getTax(),o.getDelivery(),o.getDiscount(),o.getTotal(),its.stream().map(i->new OrderItemSnapshot(i.getId(),i.getProductId(),i.getVariationId(),i.getProductName(),i.getProductCode(),i.getVariationName(),i.getImageUrl(),i.getUnitPrice(),i.getQuantity(),i.getLineSubtotal(),i.getTaxRate(),i.getTaxAmount())).toList(),new DeliverySnapshot(o.getRecipient(),mask(o.getPhone()),o.getAddressSnapshot(),o.getDeliverySnapshot()),o.getNote(),timeline(o),cancellationEligibility(o),returnEligibility(o),true);}
 private OrderSummary summary(CustomerOrder o){List<CustomerOrderItem>its=items.findByOrderIdOrderByIdAsc(o.getId());int qty=its.stream().mapToInt(CustomerOrderItem::getQuantity).sum();CustomerOrderItem first=its.isEmpty()?null:its.get(0);return new OrderSummary(o.getOrderNumber(),o.getSubmittedAt(),o.getStatus().name(),label(o.getStatus().name()),o.getPaymentStatus().name(),o.getTotal(),"BDT",qty,its.size(),first==null?null:first.getProductName(),first==null?null:first.getImageUrl(),Math.max(0,its.size()-1),o.getDeliverySnapshot(),cancellationEligibility(o).eligible(),returnEligibility(o).eligible());}
 private List<TimelineEntry> timeline(CustomerOrder o){List<CustomerOrderStatusHistory>hs=history.findByOrderIdOrderByCreatedAtAsc(o.getId());return hs.stream().map(h->new TimelineEntry(h.getStatus(),label(h.getStatus()),description(h.getStatus()),h.getCreatedAt(),true,h.getStatus().equals(o.getStatus().name()),h.getCustomerNote())).toList();}
 private EligibilityResponse cancellationEligibility(CustomerOrder o){Optional<CustomerOrderCancellationRequest>ex=cancellations.findTopByOrderIdOrderByRequestedAtDesc(o.getId());if(ex.isPresent()&&List.of(CustomerOrderCancellationRequest.Status.REQUESTED,CustomerOrderCancellationRequest.Status.UNDER_REVIEW).contains(ex.get().getStatus()))return new EligibilityResponse(false,"CANCELLATION_ALREADY_REQUESTED","A cancellation request is already active.",ex.get().getStatus().name());if(o.getStatus()==CustomerOrder.OrderStatus.PENDING_CONFIRMATION)return new EligibilityResponse(true,"ELIGIBLE","This order can request cancellation before processing starts.",ex.map(r->r.getStatus().name()).orElse(null));return new EligibilityResponse(false,"ORDER_STATUS_NOT_ELIGIBLE","This order status is not eligible for cancellation.",ex.map(r->r.getStatus().name()).orElse(null));}
 private ReturnEligibilityResponse returnEligibility(CustomerOrder o){Optional<CustomerReturnRequest>ex=returns.findByOrderIdOrderByRequestedAtDesc(o.getId()).stream().findFirst();if(o.getStatus()!=CustomerOrder.OrderStatus.DELIVERED)return new ReturnEligibilityResponse(false,"ORDER_NOT_DELIVERED","Returns are available only after delivery.",returnWindowDays,List.of(),ex.map(r->r.getStatus().name()).orElse(null));Instant delivered=history.findByOrderIdOrderByCreatedAtAsc(o.getId()).stream().filter(h->"DELIVERED".equals(h.getStatus())).map(CustomerOrderStatusHistory::getCreatedAt).reduce((a,b)->b).orElse(null);if(delivered==null)return new ReturnEligibilityResponse(false,"DELIVERED_TIMESTAMP_MISSING","Delivered timestamp is not available.",returnWindowDays,List.of(),ex.map(r->r.getStatus().name()).orElse(null));if(delivered.plus(Duration.ofDays(returnWindowDays)).isBefore(Instant.now()))return new ReturnEligibilityResponse(false,"RETURN_WINDOW_EXPIRED","The return window has expired.",returnWindowDays,List.of(),ex.map(r->r.getStatus().name()).orElse(null));List<ReturnableOrderItem>out=items.findByOrderIdOrderByIdAsc(o.getId()).stream().map(i->new ReturnableOrderItem(i.getId(),i.getProductName(),i.getVariationName(),i.getQuantity(),remainingReturnable(i))).filter(i->i.remainingReturnableQuantity()>0).toList();return new ReturnEligibilityResponse(!out.isEmpty(),out.isEmpty()?"NO_RETURNABLE_ITEMS":"ELIGIBLE",out.isEmpty()?"No returnable quantity remains.":"This delivered order has returnable items.",returnWindowDays,out,ex.map(r->r.getStatus().name()).orElse(null));}
 private int remainingReturnable(CustomerOrderItem i){Long active=returnItems.activeRequestedQuantity(i.getId(),List.of(CustomerReturnRequest.Status.REQUESTED,CustomerReturnRequest.Status.UNDER_REVIEW,CustomerReturnRequest.Status.APPROVED,CustomerReturnRequest.Status.PARTIALLY_APPROVED));return Math.max(0,i.getQuantity()-(active==null?0:active.intValue()));}
 private CancellationRequestResponse cancellationResponse(CustomerOrder o,CustomerOrderCancellationRequest r){return new CancellationRequestResponse(o.getOrderNumber(),r.getStatus().name(),r.getReasonCode().name(),r.getReasonText(),r.getRequestedAt(),"Cancellation request received. No refund, payment, stock, or accounting action has been performed.");}
 private ReturnRequestResponse returnResponse(CustomerOrder o,CustomerReturnRequest r){Map<Long,CustomerOrderItem>map=items.findByOrderIdOrderByIdAsc(o.getId()).stream().collect(Collectors.toMap(CustomerOrderItem::getId,x->x));List<ReturnRequestItemResponse>its=returnItems.findByReturnRequestIdOrderByIdAsc(r.getId()).stream().map(i->new ReturnRequestItemResponse(i.getOrderItemId(),map.get(i.getOrderItemId())==null?"Item":map.get(i.getOrderItemId()).getProductName(),i.getRequestedQuantity(),i.getReasonCode().name(),i.getReasonText())).toList();return new ReturnRequestResponse(r.getRequestNumber(),o.getOrderNumber(),r.getStatus().name(),r.getPreferredResolution().name(),r.getRequestedAt(),its,"Return request received for review. No stock, refund, or ledger action has been performed.");}
 private Sort sort(String s){return switch(s==null?"newest":s){case"oldest"->Sort.by("submittedAt").ascending();case"total_desc"->Sort.by("total").descending();case"total_asc"->Sort.by("total").ascending();default->Sort.by("submittedAt").descending();};}private CustomerOrder.OrderStatus parseOrderStatus(String v){try{return CustomerOrder.OrderStatus.valueOf(v.trim().toUpperCase());}catch(Exception e){throw err(HttpStatus.BAD_REQUEST,"INVALID_ORDER_STATUS","Unsupported order status filter.");}}private CustomerOrder.PaymentStatus parsePaymentStatus(String v){try{return CustomerOrder.PaymentStatus.valueOf(v.trim().toUpperCase());}catch(Exception e){throw err(HttpStatus.BAD_REQUEST,"INVALID_PAYMENT_STATUS","Unsupported payment status filter.");}}
 private CustomerOrderCancellationRequest.ReasonCode reason(String v){try{return CustomerOrderCancellationRequest.ReasonCode.valueOf(v.trim().toUpperCase());}catch(Exception e){throw err(HttpStatus.BAD_REQUEST,"INVALID_REASON","Unsupported cancellation reason.");}}private CustomerReturnRequestItem.ReasonCode returnReason(String v){try{return CustomerReturnRequestItem.ReasonCode.valueOf(v.trim().toUpperCase());}catch(Exception e){throw err(HttpStatus.BAD_REQUEST,"INVALID_REASON","Unsupported return reason.");}}private CustomerReturnRequest.PreferredResolution resolution(String v){try{return CustomerReturnRequest.PreferredResolution.valueOf(v.trim().toUpperCase());}catch(Exception e){throw err(HttpStatus.BAD_REQUEST,"INVALID_RESOLUTION","Unsupported preferred resolution.");}}
 private String returnNumber(){String n;do{n="RETREQ-"+DateTimeFormatter.BASIC_ISO_DATE.format(LocalDate.now())+"-"+UUID.randomUUID().toString().substring(0,8).toUpperCase();}while(returns.existsByRequestNumber(n));return n;}private String label(String s){return Arrays.stream(s.split("_")).map(x->x.charAt(0)+x.substring(1).toLowerCase()).collect(Collectors.joining(" "));}private String description(String s){return switch(s){case"PENDING_CONFIRMATION"->"Your order was submitted and is awaiting confirmation.";case"CANCELLATION_REQUESTED"->"Your cancellation request was received for review.";case"RETURN_REQUESTED"->"Your return request was received for review.";case"DELIVERED"->"The order was marked delivered.";default->label(s);};}private String mask(String p){if(p==null||p.length()<5)return p;return p.substring(0,3)+"****"+p.substring(p.length()-2);}private String clean(String s){return s==null||s.isBlank()?null:s.replaceAll("<[^>]*>","").trim();}private String money(BigDecimal v){return "BDT "+(v==null?BigDecimal.ZERO:v).setScale(2,java.math.RoundingMode.HALF_UP);}private String esc(String v){return v==null?"":v.replace("&","&amp;").replace("<","&lt;").replace(">","&gt;").replace("\"","&quot;");}private String nullToEmpty(String v){return v==null?"":v;}private String safeFile(String v){return v.replaceAll("[^A-Za-z0-9._-]","-");}private CustomerAuthException err(HttpStatus s,String c,String m){return new CustomerAuthException(s,c,m);} }
